oxy_webhelp_navlinks = {"azr_devops_recover-d30753e35184":{"topics":[{"title":"Privilege elevation for Azure DevOps recovery","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enhances the security of your Azure DevOps environment by         employing a least privilege model that limits the access granted to the minimal necessary         roles and resources.<\/p>","href":"azure_devops\/azr_devops_privilege_elevation.html","attributes":{"data-id":"azr_devops_privilege_elevation"},"menu":{"hasChildren":false},"tocID":"azr_devops_privilege_elevation-d30753e35198","topics":[]},{"title":"Azure DevOps repository settings backup and recovery","shortdesc":"<p class=\"shortdesc\">In addition to repository contents, <span class=\"ph\">RSC<\/span> backs up a curated set of         Azure DevOps repository-level settings as part of every repository snapshot and re-applies         them to the destination repository during recovery.<\/p>","href":"azure_devops\/azr_devops_settings_backup_recovery.html","attributes":{"data-id":"azr_devops_settings_backup_recovery"},"menu":{"hasChildren":false},"tocID":"azr_devops_settings_backup_recovery-d30753e35211","topics":[]},{"title":"Recovering Azure DevOps projects and repositories","shortdesc":"<p class=\"shortdesc\">Recover Azure DevOps projects and repositories from protected snapshots.<\/p>","href":"azure_devops\/azr_devops_recovering_proj_repos.html","attributes":{"data-id":"azr_devops_recovering_proj_repos"},"menu":{"hasChildren":false},"tocID":"azr_devops_recovering_proj_repos-d30753e35225","topics":[]}]}};